// Basic SystemVerilog testbench structure
module tb_counter;
  // Declare signals
  logic clk = 0;
  logic rst_n;
  logic [3:0] count;

  // Instantiate DUT
  counter dut (
    .clk   (clk),
    .rst_n (rst_n),
    .count (count)
  );

  // Clock: 10ns period
  always #5 clk = ~clk;

  initial begin
    // Reset sequence
    rst_n = 0;
    repeat(3) @(posedge clk);
    rst_n = 1;

    // Apply stimulus
    repeat(10) @(posedge clk);

    $display("Final count = %0d", count);
    $finish;
  end
endmodule

// DUT: simple AND gate
// module and_gate(input a, b, output out);
// assign out = a & b;

// TESTBENCH:
module tb_and_gate;
  logic a, b, out;

  // Instantiate DUT
  and_gate dut (.a(a), .b(b), .out(out));

  initial begin
    // Test all 4 input combinations
    a=0; b=0; #10;
    assert(out==0) else $error("FAIL: 0&0=%b",out);

    a=0; b=1; #10;
    assert(out==0) else $error("FAIL: 0&1=%b",out);

    a=1; b=0; #10;
    assert(out==0) else $error("FAIL: 1&0=%b",out);

    a=1; b=1; #10;
    assert(out==1) else $error("FAIL: 1&1=%b",out);

    $display("All AND gate tests PASSED");
    $finish;
  end
endmodule
// Key insight: for small designs, exhaustive testing is possible.
// For large designs, we need constrained-random testing.

