// FSM state verification pattern
// Drive inputs, wait for state change, check output

task send_input(input logic [1:0] cmd);
  @(posedge clk);
  cmd_in <= cmd;
  @(posedge clk);
  cmd_in <= 2'b00;
endtask

// Protocol handshake verification
task wait_for_ready;
  // Wait until slave is ready
  wait(ready == 1'b1);
  @(posedge clk);
endtask

// Check output after N cycles
task check_after(input int cycles, input logic exp_out);
  repeat(cycles) @(posedge clk);
  #1; // settle time
  assert(out == exp_out)
    else $error("Expected %b got %b", exp_out, out);
endtask

// Verifying a 3-state traffic light FSM
// States: RED(0) → GREEN(1) → YELLOW(2) → RED
// Each state lasts 30 clock cycles

module tb_traffic;
  logic clk=0, rst_n;
  logic red, green, yellow;

  traffic_light dut(.clk,.rst_n,.red,.green,.yellow);
  always #5 clk = ~clk;

  initial begin
    // Step 1: Reset
    rst_n = 0;
    repeat(2) @(posedge clk);
    rst_n = 1;
    @(posedge clk); #1;

    // Step 2: Check RED state
    assert(red==1 && green==0 && yellow==0)
      else $error("Not in RED after reset");

    // Step 3: Wait for GREEN (30 cycles)
    repeat(30) @(posedge clk); #1;
    assert(red==0 && green==1 && yellow==0)
      else $error("Not in GREEN");

    // Step 4: Wait for YELLOW
    repeat(30) @(posedge clk); #1;
    assert(red==0 && green==0 && yellow==1)
      else $error("Not in YELLOW");

    $display("Traffic light FSM PASSED");
    $finish;
  end
endmodule

