// SystemVerilog transaction class
class Packet;
  rand logic [7:0]  data;
  rand logic [3:0]  addr;
  rand logic        valid;

  // Constraint: addr must be 0-7
  constraint c_addr { addr inside {[0:7]}; }

  // Constraint: valid is mostly 1
  constraint c_valid { valid dist {1:=80, 0:=20}; }

  function void display();
    $display("Pkt: addr=%0d data=%0h valid=%b", addr, data, valid);
  endfunction
endclass

// Usage:
Packet pkt = new();
repeat(10) begin
  assert(pkt.randomize()) else $fatal("Randomize failed");
  pkt.display();
end

// Interface for an 8-bit adder
interface adder_if(input logic clk);
  logic [7:0] a, b;
  logic [8:0] result;
endinterface

// Transaction class
class AddTx;
  rand logic [7:0] a, b;
  logic [8:0] expected;
  function void compute(); expected = a + b; endfunction
endclass

// Testbench
module tb_adder;
  logic clk = 0;
  always #5 clk = ~clk;

  adder_if aif(.clk(clk));
  adder8 dut(.a(aif.a), .b(aif.b), .result(aif.result));

  AddTx tx = new();

  initial begin
    repeat(20) begin
      // Generate random transaction
      assert(tx.randomize());
      tx.compute();

      // Drive DUT
      aif.a = tx.a;
      aif.b = tx.b;
      #1;

      // Check result
      assert(aif.result == tx.expected)
        else $error("FAIL: %0d+%0d=%0d exp=%0d",
                    tx.a, tx.b, aif.result, tx.expected);
    end
    $display("20 random adder tests PASSED");
    $finish;
  end
endmodule

