// Mailbox-based producer-consumer
mailbox #(Packet) gen2drv = new();

// Generator thread — produces random packets
task generator();
  Packet pkt;
  repeat(20) begin
    pkt = new();
    assert(pkt.randomize());
    gen2drv.put(pkt);  // send to driver
  end
endtask

// Driver thread — consumes and drives DUT
task driver();
  Packet pkt;
  forever begin
    gen2drv.get(pkt);  // receive from generator
    // drive DUT with pkt
    @(posedge clk);
    data_in <= pkt.data;
    valid   <= 1;
    @(posedge clk);
    valid <= 0;
  end
endtask

// Run both in parallel
initial begin
  fork
    generator();
    driver();
  join
  $finish;
end

// Simple packet class
class Pkt;
  rand logic [7:0] data;
  logic [7:0] exp_out; // expected output
endclass

module tb_fifo;
  logic clk=0, rst_n=0;
  logic wr_en, rd_en;
  logic [7:0] wr_data, rd_data;
  logic full, empty;

  sync_fifo dut(.clk,.rst_n,.wr_en,.rd_en,
                .wr_data,.rd_data,.full,.empty);
  always #5 clk = ~clk;

  mailbox #(Pkt) gen2drv  = new();
  mailbox #(Pkt) mon2scb  = new();

  // Generator
  task generator();
    Pkt p;
    repeat(10) begin
      p = new();
      assert(p.randomize());
      gen2drv.put(p);
    end
  endtask

  // Driver — writes to FIFO
  task driver();
    Pkt p;
    repeat(10) begin
      gen2drv.get(p);
      wait(!full);
      @(posedge clk);
      wr_en <= 1; wr_data <= p.data;
      @(posedge clk);
      wr_en <= 0;
      p.exp_out = p.data; // FIFO should return same data
      mon2scb.put(p);
    end
  endtask

  // Scoreboard — checks FIFO output
  task scoreboard();
    Pkt p;
    repeat(10) begin
      mon2scb.get(p);
      // Read from FIFO
      wait(!empty);
      @(posedge clk);
      rd_en <= 1;
      @(posedge clk);
      rd_en <= 0;
      #1;
      assert(rd_data == p.exp_out)
        else $error("SCB FAIL: got %0h exp %0h", rd_data, p.exp_out);
    end
  endtask

  initial begin
    rst_n=0; repeat(2) @(posedge clk); rst_n=1;
    fork generator(); driver(); scoreboard(); join
    $display("FIFO test PASSED"); $finish;
  end
endmodule

