// VALID/READY handshake assertions

// 1. Once valid asserted, stays until ready
property valid_stable;
  @(posedge clk)
  (valid && !ready) |=> valid; // valid must stay high
endproperty
assert property (valid_stable)
  else $error("valid deasserted before ready!");

// 2. After ready+valid, data must change next cycle
property data_changes;
  @(posedge clk)
  (valid && ready) |=> (data != $past(data));
endproperty

// 3. No X on data when valid
assert property (@(posedge clk)
  valid |-> !$isunknown(data))
  else $error("X on data during valid!");

// 4. Sequence: req then ack within 3 cycles
sequence req_ack;
  req ##[1:3] ack;
endsequence
assert property (@(posedge clk) req |-> req_ack);

// AXI4-Lite Write Channel Assertions
module axi_assertions(
  input logic clk, rst_n,
  input logic awvalid, awready,
  input logic wvalid, wready,
  input logic bvalid, bready,
  input logic [31:0] awaddr, wdata
);

  // AW channel: valid stays until ready
  property aw_valid_stable;
    @(posedge clk) disable iff (!rst_n)
    (awvalid && !awready) |=> awvalid;
  endproperty
  assert property (aw_valid_stable)
    else $error("AWVALID dropped before AWREADY");

  // No X on address during valid
  assert property (@(posedge clk) disable iff (!rst_n)
    awvalid |-> !$isunknown(awaddr))
    else $error("X on AWADDR during AWVALID");

  // W channel: valid stays until ready
  property w_valid_stable;
    @(posedge clk) disable iff (!rst_n)
    (wvalid && !wready) |=> wvalid;
  endproperty
  assert property (w_valid_stable)
    else $error("WVALID dropped before WREADY");

  // BVALID must eventually come (within 10 cycles of write)
  property write_response;
    @(posedge clk) disable iff (!rst_n)
    (awvalid && awready) |-> ##[1:10] bvalid;
  endproperty
  assert property (write_response)
    else $error("No BVALID within 10 cycles of write");

endmodule

