// Functional coverage for an 8-bit data bus
covergroup data_cg @(posedge clk);
  // Track data values in meaningful ranges
  cp_data: coverpoint data {
    bins zero      = {0};
    bins low       = {[1:63]};
    bins mid       = {[64:191]};
    bins high      = {[192:254]};
    bins max_val   = {255};
  }

  // Track op codes
  cp_op: coverpoint op {
    bins add  = {2'b00};
    bins sub  = {2'b01};
    bins and_ = {2'b10};
    bins or_  = {2'b11};
  }

  // Cross: every op with every data range
  cx_data_op: cross cp_data, cp_op;
endgroup

// Instantiate and use
data_cg cg_inst = new();
// Coverage auto-samples at posedge clk
// Check coverage:
// $display("Coverage: %0.2f%%", cg_inst.get_coverage());

// FIFO Coverage Model
covergroup fifo_cg @(posedge clk);
  // Fill level coverage
  cp_fill: coverpoint count {
    bins empty    = {0};
    bins quarter  = {[1:1]};  // 1/4 of 4-deep FIFO
    bins half     = {[2:2]};
    bins threequarter = {[3:3]};
    bins full_val = {4};
  }

  // Operation coverage
  cp_op: coverpoint {wr_en, rd_en} {
    bins write_only  = {2'b10};
    bins read_only   = {2'b01};
    bins both        = {2'b11}; // simultaneous R+W
    bins idle        = {2'b00};
  }

  // Write data value coverage
  cp_wdata: coverpoint wr_data {
    bins zero    = {8'h00};
    bins max     = {8'hFF};
    bins others  = default;
  }

  // Cross: operation vs fill level
  cx_op_fill: cross cp_op, cp_fill;
endgroup

// In testbench:
fifo_cg cg = new();
// Runs random stimulus until coverage closes...
// final: $display("FIFO Coverage: %.1f%%", cg.get_coverage());

