// Minimal UVM Driver
class my_driver extends uvm_driver #(my_tx);
  `uvm_component_utils(my_driver)

  virtual dut_if vif; // virtual interface to DUT

  function new(string name, uvm_component parent);
    super.new(name, parent);
  endfunction

  function void build_phase(uvm_phase phase);
    super.build_phase(phase);
    // Get virtual interface from config_db
    if (!uvm_config_db #(virtual dut_if)::get(
          this, "", "vif", vif))
      `uvm_fatal("NO_VIF", "Virtual interface not set")
  endfunction

  task run_phase(uvm_phase phase);
    my_tx req;
    forever begin
      seq_item_port.get_next_item(req); // get from sequencer
      // drive req onto vif
      @(posedge vif.clk);
      vif.data  <= req.data;
      vif.valid <= 1;
      @(posedge vif.clk);
      vif.valid <= 0;
      seq_item_port.item_done(); // tell sequencer done
    end
  endtask
endclass

