// Scoreboard with TLM analysis
class my_scoreboard extends uvm_scoreboard;
  `uvm_component_utils(my_scoreboard)

  // Port to receive observed transactions from monitor
  uvm_analysis_imp #(my_tx, my_scoreboard) analysis_export;

  // Reference model queue
  my_tx exp_queue[$];

  function new(string name, uvm_component parent);
    super.new(name, parent);
  endfunction

  function void build_phase(uvm_phase phase);
    analysis_export = new("analysis_export", this);
  endfunction

  // Called by monitor when it observes a transaction
  function void write(my_tx observed);
    my_tx expected;
    if (exp_queue.size() == 0) begin
      `uvm_error("SCB", "Unexpected transaction")
      return;
    end
    expected = exp_queue.pop_front();
    if (observed.data !== expected.data)
      `uvm_error("SCB", $sformatf(
        "MISMATCH: got %0h exp %0h",
        observed.data, expected.data))
    else
      `uvm_info("SCB", "MATCH", UVM_LOW)
  endfunction
endclass

// UVM Environment connecting all pieces
class fifo_env extends uvm_env;
  `uvm_component_utils(fifo_env)

  fifo_agent    agent;
  fifo_scoreboard scb;

  function new(string name, uvm_component parent);
    super.new(name, parent);
  endfunction

  function void build_phase(uvm_phase phase);
    agent = fifo_agent::type_id::create("agent", this);
    scb   = fifo_scoreboard::type_id::create("scb", this);
  endfunction

  function void connect_phase(uvm_phase phase);
    // Connect monitor's analysis port to scoreboard
    agent.monitor.ap.connect(scb.analysis_export);
  endfunction
endclass

