function void write(fifo_tx tx);
  if (tx.rd_data !== expected_data) begin
    `uvm_error("SCB",
      $sformatf("[%0t] FAIL: got=0x%0h exp=0x%0h rd_ptr=%0d",
      $time, tx.rd_data, expected_data, tx.rd_ptr))
