// Back-pressure pattern
task apply_backpressure(int max_wait);
  int delay = $urandom_range(0, max_wait);
  ready <= 0;
  repeat(delay) @(posedge clk);
  ready <= 1;
endtask

// Timeout check pattern
task wait_for_response_timeout(int timeout_cycles);
  fork
    begin : wait_thread
      wait(response_valid == 1);
    end
    begin : timeout_thread
      repeat(timeout_cycles) @(posedge clk);
      `uvm_fatal("TIMEOUT",
        $sformatf("No response after %0d cycles", timeout_cycles))
    end
  join_any
  disable fork; // kill the other thread
endtask

