// UART RX Verification — key tasks

// Task: send one UART byte at 9600 baud (50MHz clk = 5208 cycles/bit)
localparam BAUD_PERIOD = 5208;

task send_uart_byte(input logic [7:0] data, input logic parity);
  // Start bit
  rx_line = 0;
  repeat(BAUD_PERIOD) @(posedge clk);

  // Data bits (LSB first)
  for (int i = 0; i < 8; i++) begin
    rx_line = data[i];
    repeat(BAUD_PERIOD) @(posedge clk);
  end

  // Parity bit (even parity)
  rx_line = parity;
  repeat(BAUD_PERIOD) @(posedge clk);

  // Stop bit
  rx_line = 1;
  repeat(BAUD_PERIOD) @(posedge clk);
endtask

// Test: correct parity → data_valid asserted
send_uart_byte(8'hA5, ^8'hA5); // even parity
@(posedge data_valid);
assert(rx_data == 8'hA5);
assert(parity_err == 0);

// Test: wrong parity → parity_err asserted
send_uart_byte(8'hA5, ~(^8'hA5)); // WRONG parity
@(posedge clk); #1;
assert(parity_err == 1);

