// Lab 9: AXI4-Lite Write Channel Testbench
module tb_axi_write;
  logic clk=0, rst_n;
  logic awvalid, awready;
  logic [7:0] awaddr;
  logic wvalid, wready;
  logic [31:0] wdata;
  logic bvalid, bready;
  logic [1:0] bresp;

  axi_slave dut(.*);
  always #5 clk = ~clk;

  // Task: AXI write transaction
  task axi_write(input logic [7:0] addr,
                 input logic [31:0] data,
                 input int bp_cycles = 0);
    // AW channel: drive address
    @(posedge clk);
    awvalid <= 1;
    awaddr  <= addr;
    // Wait for awready
    wait(awready == 1);
    @(posedge clk);
    awvalid <= 0;

    // W channel: drive data
    @(posedge clk);
    wvalid <= 1;
    wdata  <= data;
    // Wait for wready
    wait(wready == 1);
    @(posedge clk);
    wvalid <= 0;

    // B channel: apply back-pressure then accept
    bready <= 0;
    repeat(bp_cycles) @(posedge clk); // back-pressure
    bready <= 1;
    // Wait for bvalid
    wait(bvalid == 1);
    @(posedge clk); #1;
    // Check response
    assert(bresp == 2'b00)
      else $error("Non-OKAY response: %0b", bresp);
    bready <= 0;
  endtask

  initial begin
    rst_n=0; awvalid=0; wvalid=0; bready=0;
    repeat(3) @(posedge clk);
    rst_n=1;

    // Test 1: 5 normal writes
    repeat(5) begin
      axi_write($urandom_range(0,15)*4, $urandom, 0);
    end

    // Test 2: 5 writes with back-pressure on B channel
    repeat(5) begin
      axi_write($urandom_range(0,15)*4, $urandom, 5);
    end

    $display("AXI Write tests PASSED");
    $finish;
  end
endmodule

