// Most common interview question: FIFO testbench
// Write this in under 20 minutes:

module tb_fifo_interview;
  logic clk=0, rst_n;
  logic wr_en, rd_en, full, empty;
  logic [7:0] wr_data, rd_data;

  sync_fifo dut(.*);
  always #5 clk = ~clk;

  // Reference queue (golden model)
  logic [7:0] ref_q[$];

  initial begin
    rst_n=0; wr_en=0; rd_en=0;
    repeat(2) @(posedge clk); rst_n=1;

    // Write 4 items
    repeat(4) begin
      wait(!full);
      @(posedge clk);
      wr_en <= 1;
      wr_data <= $urandom;
      ref_q.push_back(wr_data);
    end
    @(posedge clk); wr_en<=0;

    // Read and check 4 items
    repeat(4) begin
      wait(!empty);
      @(posedge clk); rd_en<=1;
      @(posedge clk); rd_en<=0;
      #1;
      assert(rd_data == ref_q.pop_front())
        else $error("FIFO data mismatch");
    end

    $display("FIFO interview test PASSED");
    $finish;
  end
endmodule

// Interview Q1: SVA for req → ack within 1-5 cycles
property req_ack_timeout;
  @(posedge clk) disable iff (!rst_n)
  req |-> ##[1:5] ack;
endproperty
assert property (req_ack_timeout)
  else $error("ACK did not come within 5 cycles of REQ");

// Interview Q2: assert vs assume
// assert: property must hold — violation = error
// assume: property assumed true — constrains formal tool input
// In simulation: assume behaves like assert
// In formal: assume constrains input space

// Interview Q3: Verify reset
initial begin
  rst_n = 1; @(posedge clk); // normal operation
  rst_n = 0; @(posedge clk); // apply reset
  #1;
  // Check all outputs are at reset values
  assert(out == 0) else $error("Reset failed: out=%0h", out);
  assert(state == IDLE) else $error("Reset: wrong state");
  rst_n = 1; // release
end

// Interview Q4: X propagation root causes
// 1. Uninitialized registers (no reset)
// 2. Multiple drivers on same wire
// 3. Reading FIFO when empty (undefined rd_data)
// Fix: always reset, check for multiple drivers, guard reads

// Interview Q5: UVM phases in order
// build → connect → start_of_simulation →
// run (reset_phase → main_phase → shutdown_phase) →
// extract → check → report

