// Lab 11: Classic FIFO Interview Testbench
module tb_fifo_classic;
  logic clk=0, rst_n;
  logic wr_en, rd_en;
  logic [7:0] wr_data, rd_data;
  logic full, empty;
  int err_count = 0;

  sync_fifo dut(.clk,.rst_n,.wr_en,.rd_en,
                .wr_data,.rd_data,.full,.empty);
  always #5 clk = ~clk;

  // Golden reference queue
  logic [7:0] ref_q[$];

  // Task: write one item
  task fifo_write(input logic [7:0] data);
    wait(!full);
    @(posedge clk);
    wr_en   <= 1;
    wr_data <= data;
    ref_q.push_back(data);
    @(posedge clk);
    wr_en <= 0;
  endtask

  // Task: read and check one item
  task fifo_read();
    logic [7:0] expected;
    wait(!empty);
    @(posedge clk);
    rd_en <= 1;
    @(posedge clk);
    rd_en <= 0;
    #1;
    expected = ref_q.pop_front();
    if (rd_data !== expected) begin
      $display("FAIL: got=%0h exp=%0h", rd_data, expected);
      err_count++;
    end
  endtask

  initial begin
    rst_n=0; wr_en=0; rd_en=0;
    repeat(2) @(posedge clk);
    rst_n=1;

    // Test 1: Write 4, read 4
    repeat(4) fifo_write($urandom);
    repeat(4) fifo_read();

    // Test 2: Simultaneous read+write
    fifo_write($urandom);
    // write and read simultaneously
    fork
      fifo_write($urandom);
      fifo_read();
    join

    // Final report
    if (err_count == 0)
      $display("** TEST PASSED **");
    else
      $display("** TEST FAILED: %0d errors **", err_count);

    $finish;
  end
endmodule

