// Lab 12: Final Boss — Complete UVM AXI-Lite Agent
import uvm_pkg::*;
`include "uvm_macros.svh"

// ── Transaction ──────────────────────────────────────────────
class axi_tx extends uvm_sequence_item;
  `uvm_object_utils(axi_tx)

  rand logic [7:0]  addr;
  rand logic [31:0] data;
  logic [1:0]       resp; // captured by monitor

  // Constraint: word-aligned address
  constraint c_align { addr[1:0] == 2'b00; }

  function new(string name="axi_tx");
    super.new(name);
  endfunction
endclass

// ── Sequence ─────────────────────────────────────────────────
class axi_write_seq extends uvm_sequence #(axi_tx);
  `uvm_object_utils(axi_write_seq)

  function new(string name="axi_write_seq");
    super.new(name);
  endfunction

  task body();
    axi_tx tx;
    repeat(20) begin
      tx = axi_tx::type_id::create("tx");
      start_item(tx);
      assert(tx.randomize());
      finish_item(tx);
    end
  endtask
endclass

// ── Driver ───────────────────────────────────────────────────
class axi_driver extends uvm_driver #(axi_tx);
  `uvm_component_utils(axi_driver)

  virtual axi_if vif;

  function new(string name, uvm_component parent);
    super.new(name, parent);
  endfunction

  function void build_phase(uvm_phase phase);
    super.build_phase(phase);
    if (!uvm_config_db #(virtual axi_if)::get(
          this, "", "vif", vif))
      `uvm_fatal("NO_VIF", "AXI interface not set")
  endfunction

  task run_phase(uvm_phase phase);
    axi_tx req;
    // Initialize signals
    vif.awvalid <= 0; vif.wvalid <= 0; vif.bready <= 0;
    @(posedge vif.rst_n); // wait for reset release

    forever begin
      seq_item_port.get_next_item(req);

      // Drive AW channel
      @(posedge vif.clk);
      vif.awvalid <= 1;
      vif.awaddr  <= req.addr;
      wait(vif.awready);
      @(posedge vif.clk);
      vif.awvalid <= 0;

      // Drive W channel
      @(posedge vif.clk);
      vif.wvalid <= 1;
      vif.wdata  <= req.data;
      wait(vif.wready);
      @(posedge vif.clk);
      vif.wvalid <= 0;

      // Accept B response
      vif.bready <= 1;
      wait(vif.bvalid);
      @(posedge vif.clk);
      req.resp = vif.bresp;
      vif.bready <= 0;

      seq_item_port.item_done();
    end
  endtask
endclass

// ── Monitor ──────────────────────────────────────────────────
class axi_monitor extends uvm_monitor;
  `uvm_component_utils(axi_monitor)

  virtual axi_if vif;
  uvm_analysis_port #(axi_tx) ap;

  function new(string name, uvm_component parent);
    super.new(name, parent);
  endfunction

  function void build_phase(uvm_phase phase);
    super.build_phase(phase);
    ap = new("ap", this);
    if (!uvm_config_db #(virtual axi_if)::get(
          this, "", "vif", vif))
      `uvm_fatal("NO_VIF", "AXI interface not set")
  endfunction

  task run_phase(uvm_phase phase);
    axi_tx tx;
    forever begin
      // Wait for completed write (bvalid + bready)
      @(posedge vif.clk);
      if (vif.bvalid && vif.bready) begin
        tx = axi_tx::type_id::create("tx");
        tx.resp = vif.bresp;
        tx.addr = vif.awaddr; // captured earlier
        ap.write(tx); // broadcast to scoreboard
      end
    end
  endtask
endclass
